import{_ as s,o as i,c as a,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"ClawHub","description":"","frontmatter":{"summary":"ClawHub guide: public skills registry + CLI workflows","read_when":["Introducing ClawHub to new users","Installing, searching, or publishing skills","Explaining ClawHub CLI flags and sync behavior"],"title":"ClawHub"},"headers":[],"relativePath":"tools/clawhub.md","filePath":"tools/clawhub.md","lastUpdated":null}'),t={name:"tools/clawhub.md"};function n(o,e,r,d,c,h){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="clawhub" tabindex="-1"><a class="header-anchor" href="#clawhub">#</a> ClawHub</h1><p>ClawHub is the <strong>public skill registry for OpenSoul</strong>. It is a free service: all skills are public, open, and visible to everyone for sharing and reuse. A skill is just a folder with a <code>SKILL.md</code> file (plus supporting text files). You can browse skills in the web app or use the CLI to search, install, update, and publish skills.</p><p>Site: <a href="https://clawhub.ai" target="_blank" rel="noreferrer">clawhub.ai</a></p><h2 id="what-clawhub-is" tabindex="-1"><a class="header-anchor" href="#what-clawhub-is">#</a> What ClawHub is</h2><ul><li>A public registry for OpenSoul skills.</li><li>A versioned store of skill bundles and metadata.</li><li>A discovery surface for search, tags, and usage signals.</li></ul><h2 id="how-it-works" tabindex="-1"><a class="header-anchor" href="#how-it-works">#</a> How it works</h2><ol><li>A user publishes a skill bundle (files + metadata).</li><li>ClawHub stores the bundle, parses metadata, and assigns a version.</li><li>The registry indexes the skill for search and discovery.</li><li>Users browse, download, and install skills in OpenSoul.</li></ol><h2 id="what-you-can-do" tabindex="-1"><a class="header-anchor" href="#what-you-can-do">#</a> What you can do</h2><ul><li>Publish new skills and new versions of existing skills.</li><li>Discover skills by name, tags, or search.</li><li>Download skill bundles and inspect their files.</li><li>Report skills that are abusive or unsafe.</li><li>If you are a moderator, hide, unhide, delete, or ban.</li></ul><h2 id="who-this-is-for-beginner-friendly" tabindex="-1"><a class="header-anchor" href="#who-this-is-for-beginner-friendly">#</a> Who this is for (beginner-friendly)</h2><p>If you want to add new capabilities to your OpenSoul agent, ClawHub is the easiest way to find and install skills. You do not need to know how the backend works. You can:</p><ul><li>Search for skills by plain language.</li><li>Install a skill into your workspace.</li><li>Update skills later with one command.</li><li>Back up your own skills by publishing them.</li></ul><h2 id="quick-start-non-technical" tabindex="-1"><a class="header-anchor" href="#quick-start-non-technical">#</a> Quick start (non-technical)</h2><ol><li>Install the CLI (see next section).</li><li>Search for something you need: <ul><li><code>clawhub search &quot;calendar&quot;</code></li></ul></li><li>Install a skill: <ul><li><code>clawhub install &lt;skill-slug&gt;</code></li></ul></li><li>Start a new OpenSoul session so it picks up the new skill.</li></ol><h2 id="install-the-cli" tabindex="-1"><a class="header-anchor" href="#install-the-cli">#</a> Install the CLI</h2><p>Pick one:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> i</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clawhub</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clawhub</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="how-it-fits-into-opensoul" tabindex="-1"><a class="header-anchor" href="#how-it-fits-into-opensoul">#</a> How it fits into OpenSoul</h2><p>By default, the CLI installs skills into <code>./skills</code> under your current working directory. If a OpenSoul workspace is configured, <code>clawhub</code> falls back to that workspace unless you override <code>--workdir</code> (or <code>CLAWHUB_WORKDIR</code>). OpenSoul loads workspace skills from <code>&lt;workspace&gt;/skills</code> and will pick them up in the <strong>next</strong> session. If you already use <code>~/.opensoul/skills</code> or bundled skills, workspace skills take precedence.</p><p>For more detail on how skills are loaded, shared, and gated, see <a href="/docs/tools/skills">Skills</a>.</p><h2 id="skill-system-overview" tabindex="-1"><a class="header-anchor" href="#skill-system-overview">#</a> Skill system overview</h2><p>A skill is a versioned bundle of files that teaches OpenSoul how to perform a specific task. Each publish creates a new version, and the registry keeps a history of versions so users can audit changes.</p><p>A typical skill includes:</p><ul><li>A <code>SKILL.md</code> file with the primary description and usage.</li><li>Optional configs, scripts, or supporting files used by the skill.</li><li>Metadata such as tags, summary, and install requirements.</li></ul><p>ClawHub uses metadata to power discovery and safely expose skill capabilities. The registry also tracks usage signals (such as stars and downloads) to improve ranking and visibility.</p><h2 id="what-the-service-provides-features" tabindex="-1"><a class="header-anchor" href="#what-the-service-provides-features">#</a> What the service provides (features)</h2><ul><li><strong>Public browsing</strong> of skills and their <code>SKILL.md</code> content.</li><li><strong>Search</strong> powered by embeddings (vector search), not just keywords.</li><li><strong>Versioning</strong> with semver, changelogs, and tags (including <code>latest</code>).</li><li><strong>Downloads</strong> as a zip per version.</li><li><strong>Stars and comments</strong> for community feedback.</li><li><strong>Moderation</strong> hooks for approvals and audits.</li><li><strong>CLI-friendly API</strong> for automation and scripting.</li></ul><h2 id="security-and-moderation" tabindex="-1"><a class="header-anchor" href="#security-and-moderation">#</a> Security and moderation</h2><p>ClawHub is open by default. Anyone can upload skills, but a GitHub account must be at least one week old to publish. This helps slow down abuse without blocking legitimate contributors.</p><p>Reporting and moderation:</p><ul><li>Any signed in user can report a skill.</li><li>Report reasons are required and recorded.</li><li>Each user can have up to 20 active reports at a time.</li><li>Skills with more than 3 unique reports are auto hidden by default.</li><li>Moderators can view hidden skills, unhide them, delete them, or ban users.</li><li>Abusing the report feature can result in account bans.</li></ul><p>Interested in becoming a moderator? Ask in the OpenSoul Discord and contact a moderator or maintainer.</p><h2 id="cli-commands-and-parameters" tabindex="-1"><a class="header-anchor" href="#cli-commands-and-parameters">#</a> CLI commands and parameters</h2><p>Global options (apply to all commands):</p><ul><li><code>--workdir &lt;dir&gt;</code>: Working directory (default: current dir; falls back to OpenSoul workspace).</li><li><code>--dir &lt;dir&gt;</code>: Skills directory, relative to workdir (default: <code>skills</code>).</li><li><code>--site &lt;url&gt;</code>: Site base URL (browser login).</li><li><code>--registry &lt;url&gt;</code>: Registry API base URL.</li><li><code>--no-input</code>: Disable prompts (non-interactive).</li><li><code>-V, --cli-version</code>: Print CLI version.</li></ul><p>Auth:</p><ul><li><code>clawhub login</code> (browser flow) or <code>clawhub login --token &lt;token&gt;</code></li><li><code>clawhub logout</code></li><li><code>clawhub whoami</code></li></ul><p>Options:</p><ul><li><code>--token &lt;token&gt;</code>: Paste an API token.</li><li><code>--label &lt;label&gt;</code>: Label stored for browser login tokens (default: <code>CLI token</code>).</li><li><code>--no-browser</code>: Do not open a browser (requires <code>--token</code>).</li></ul><p>Search:</p><ul><li><code>clawhub search &quot;query&quot;</code></li><li><code>--limit &lt;n&gt;</code>: Max results.</li></ul><p>Install:</p><ul><li><code>clawhub install &lt;slug&gt;</code></li><li><code>--version &lt;version&gt;</code>: Install a specific version.</li><li><code>--force</code>: Overwrite if the folder already exists.</li></ul><p>Update:</p><ul><li><code>clawhub update &lt;slug&gt;</code></li><li><code>clawhub update --all</code></li><li><code>--version &lt;version&gt;</code>: Update to a specific version (single slug only).</li><li><code>--force</code>: Overwrite when local files do not match any published version.</li></ul><p>List:</p><ul><li><code>clawhub list</code> (reads <code>.clawhub/lock.json</code>)</li></ul><p>Publish:</p><ul><li><code>clawhub publish &lt;path&gt;</code></li><li><code>--slug &lt;slug&gt;</code>: Skill slug.</li><li><code>--name &lt;name&gt;</code>: Display name.</li><li><code>--version &lt;version&gt;</code>: Semver version.</li><li><code>--changelog &lt;text&gt;</code>: Changelog text (can be empty).</li><li><code>--tags &lt;tags&gt;</code>: Comma-separated tags (default: <code>latest</code>).</li></ul><p>Delete/undelete (owner/admin only):</p><ul><li><code>clawhub delete &lt;slug&gt; --yes</code></li><li><code>clawhub undelete &lt;slug&gt; --yes</code></li></ul><p>Sync (scan local skills + publish new/updated):</p><ul><li><code>clawhub sync</code></li><li><code>--root &lt;dir...&gt;</code>: Extra scan roots.</li><li><code>--all</code>: Upload everything without prompts.</li><li><code>--dry-run</code>: Show what would be uploaded.</li><li><code>--bump &lt;type&gt;</code>: <code>patch|minor|major</code> for updates (default: <code>patch</code>).</li><li><code>--changelog &lt;text&gt;</code>: Changelog for non-interactive updates.</li><li><code>--tags &lt;tags&gt;</code>: Comma-separated tags (default: <code>latest</code>).</li><li><code>--concurrency &lt;n&gt;</code>: Registry checks (default: 4).</li></ul><h2 id="common-workflows-for-agents" tabindex="-1"><a class="header-anchor" href="#common-workflows-for-agents">#</a> Common workflows for agents</h2><h3 id="search-for-skills" tabindex="-1"><a class="header-anchor" href="#search-for-skills">#</a> Search for skills</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> search</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;postgres backups&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="download-new-skills" tabindex="-1"><a class="header-anchor" href="#download-new-skills">#</a> Download new skills</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill-pack</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="update-installed-skills" tabindex="-1"><a class="header-anchor" href="#update-installed-skills">#</a> Update installed skills</h3><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> update</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="back-up-your-skills-publish-or-sync" tabindex="-1"><a class="header-anchor" href="#back-up-your-skills-publish-or-sync">#</a> Back up your skills (publish or sync)</h3><p>For a single skill folder:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> publish</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-skill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --slug</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-skill</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --name</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;My Skill&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --version</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1.0.0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --tags</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> latest</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>To scan and back up many skills at once:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">clawhub</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --all</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="advanced-details-technical" tabindex="-1"><a class="header-anchor" href="#advanced-details-technical">#</a> Advanced details (technical)</h2><h3 id="versioning-and-tags" tabindex="-1"><a class="header-anchor" href="#versioning-and-tags">#</a> Versioning and tags</h3><ul><li>Each publish creates a new <strong>semver</strong> <code>SkillVersion</code>.</li><li>Tags (like <code>latest</code>) point to a version; moving tags lets you roll back.</li><li>Changelogs are attached per version and can be empty when syncing or publishing updates.</li></ul><h3 id="local-changes-vs-registry-versions" tabindex="-1"><a class="header-anchor" href="#local-changes-vs-registry-versions">#</a> Local changes vs registry versions</h3><p>Updates compare the local skill contents to registry versions using a content hash. If local files do not match any published version, the CLI asks before overwriting (or requires <code>--force</code> in non-interactive runs).</p><h3 id="sync-scanning-and-fallback-roots" tabindex="-1"><a class="header-anchor" href="#sync-scanning-and-fallback-roots">#</a> Sync scanning and fallback roots</h3><p><code>clawhub sync</code> scans your current workdir first. If no skills are found, it falls back to known legacy locations (for example <code>~/opensoul/skills</code> and <code>~/.opensoul/skills</code>). This is designed to find older skill installs without extra flags.</p><h3 id="storage-and-lockfile" tabindex="-1"><a class="header-anchor" href="#storage-and-lockfile">#</a> Storage and lockfile</h3><ul><li>Installed skills are recorded in <code>.clawhub/lock.json</code> under your workdir.</li><li>Auth tokens are stored in the ClawHub CLI config file (override via <code>CLAWHUB_CONFIG_PATH</code>).</li></ul><h3 id="telemetry-install-counts" tabindex="-1"><a class="header-anchor" href="#telemetry-install-counts">#</a> Telemetry (install counts)</h3><p>When you run <code>clawhub sync</code> while logged in, the CLI sends a minimal snapshot to compute install counts. You can disable this entirely:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">export</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> CLAWHUB_DISABLE_TELEMETRY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="environment-variables" tabindex="-1"><a class="header-anchor" href="#environment-variables">#</a> Environment variables</h2><ul><li><code>CLAWHUB_SITE</code>: Override the site URL.</li><li><code>CLAWHUB_REGISTRY</code>: Override the registry API URL.</li><li><code>CLAWHUB_CONFIG_PATH</code>: Override where the CLI stores the token/config.</li><li><code>CLAWHUB_WORKDIR</code>: Override the default workdir.</li><li><code>CLAWHUB_DISABLE_TELEMETRY=1</code>: Disable telemetry on <code>sync</code>.</li></ul>',80)])])}const k=s(t,[["render",n]]);export{u as __pageData,k as default};
